const SWE_SOURCE_DOC = '17PtuhikNt-NX-ifnxv-dVv-e_y9FOcKn3hV8C2qH5yY';
const BDM_SOURCE_DOC = '1I1Z0sU0vaIFFB6wBrEqPqpOwdshg0_BsTxu69359JI0';
const SOURCE_SHEET = 'Responses';
const emailPattern = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

function extractRowNumber(item) {
  const candidates = [item['Row Number'], item.rowNumber, item.row_number];
  for (const value of candidates) {
    const parsed = Number(value);
    if (Number.isFinite(parsed) && parsed > 0) return parsed;
  }
  return null;
}

function extractRole(item) {
  const rawRole = String(item.position || item.role || item.applied_role || '').trim().toUpperCase();
  if (rawRole.includes('BDM') || rawRole.includes('BUSINESS')) return 'BDM';
  return 'SWE';
}

function extractResumeUrl(item) {
  return String(item.resume_url || item.resumeLink || item.resume || '').trim();
}

function extractName(item) {
  return String(item.name || item.full_name || item.candidate_name || '').trim();
}

function extractEmail(item) {
  return String(item.email || item.email_address || item.applicant_email || '').trim().toLowerCase();
}

return items.map((entry) => {
  const source = entry.json || {};
  const role = extractRole(source);
  const name = extractName(source);
  const email = extractEmail(source);
  const resumeUrl = extractResumeUrl(source);
  const sourceRowNumber = extractRowNumber(source);
  const sourceSheetName = SOURCE_SHEET;
  const sourceDocumentId = role === 'BDM' ? BDM_SOURCE_DOC : SWE_SOURCE_DOC;
  const validationIssues = [];

  if (!name) validationIssues.push('missing_name');
  if (!email || !emailPattern.test(email)) validationIssues.push('invalid_email');
  if (!resumeUrl) validationIssues.push('missing_resume_url');
  if (!sourceRowNumber) validationIssues.push('missing_row_number');

  const candidateKey = [role, email || 'unknown-email', sourceRowNumber || 'unknown-row'].join('-');

  return {
    json: {
      candidateKey,
      candidate_key: candidateKey,
      name,
      email,
      role,
      resumeUrl,
      resume_url: resumeUrl,
      sourceRowNumber,
      source_row_number: sourceRowNumber,
      sourceSheetName,
      source_sheet: sourceSheetName,
      sourceDocumentId,
      processed: String(source.processed || '').toLowerCase() === 'true',
      validationStatus: validationIssues.length === 0 ? 'valid' : 'invalid',
      validation_issues: validationIssues.join(', '),
      validationIssues: validationIssues.join(', '),
      hiringManagerEmail: String(source.hiringManagerEmail || 'trillesfate@gmail.com'),
      interviewCalendarId: String(source.interviewCalendarId || 'primary'),
      sourceRaw: source
    }
  };
});

function extractGoogleDriveFileId(url) {
  const text = String(url || '').trim();
  const patterns = [
    /id=([-\w]{25,})/,
    /\/d\/([-\w]{25,})/,
    /file\/d\/([-\w]{25,})/,
    /([-\w]{25,})/
  ];

  for (const pattern of patterns) {
    const match = text.match(pattern);
    if (match) return match[1] || match[0];
  }

  return null;
}

return items.map((entry) => {
  const resumeFileId = extractGoogleDriveFileId(entry.json.resumeUrl);
  return {
    json: {
      ...entry.json,
      resume_file_id: resumeFileId,
      resumeFileId,
      screeningPrompt: entry.json.role === 'BDM'
        ? 'Evaluate a Business Development Manager candidate on client acquisition, pipeline building, commercial judgment, communication, negotiation, ownership, and closing ability.'
        : 'Evaluate a Software Engineer candidate on problem solving, code quality, system design exposure, ownership, debugging ability, collaboration, and delivery.'
    }
  };
});

const safeParse = (text) => {
if (!text) return null;
if (typeof text === 'object') return text;
try { return JSON.parse(text); } catch (e) {}
const s = String(text).trim();
const start = s.indexOf('{');
const end = s.lastIndexOf('}');
if (start >= 0 && end > start) {
try { return JSON.parse(s.slice(start, end + 1)); } catch (e) {}
}
return { rawText: s };
};

return $input.all().map(item => {
const raw = item.json || {};

// prefer merged fields created by Merge Gemini Response with Context
const candidateText =
raw.geminiText ||
raw.screening_raw ||
raw.geminiResponse?.candidates?.[0]?.content?.parts?.[0]?.text ||
raw.candidates?.[0]?.content?.parts?.[0]?.text ||
raw.text ||
raw.body ||
'';

const parsed = safeParse(candidateText) || {};

// normalized parsed fields
const parsedScore = Number(parsed.score ?? parsed.scoring ?? parsed.score_raw ?? 0);
const parsedClassification = String(parsed.classification || parsed.class || '').toLowerCase();
const classification = ['strong','average','weak'].includes(parsedClassification) ? parsedClassification : (raw.classification || 'average');

const out = {
...raw,
gemini_parsed: parsed,
score: parsedScore || Number(raw.score || 0),
classification,
summary: String(parsed.summary || parsed.screeningSummary || raw.summary || '').trim(),
strengths: Array.isArray(parsed.strengths) ? parsed.strengths.join('; ') : String(parsed.strengths || raw.strengths || '').trim(),
concerns: Array.isArray(parsed.concerns) ? parsed.concerns.join('; ') : String(parsed.concerns || raw.concerns || '').trim(),
recommendation: String(parsed.interview_recommendation || parsed.recommendation || raw.recommendation || '').trim(),
screening_raw: candidateText,
contact_status: raw.contact_status || raw.contactStatus || 'pending'
};

// Ensure source context still present
out.sourceDocumentId = out.sourceDocumentId || out.source_document_id || raw.sourceDocumentId || raw.source_document_id;
out.source_row_number = out.source_row_number || out.sourceRowNumber || raw.source_row_number || raw.sourceRowNumber;
out.sourceSheetName = out.sourceSheetName || out.source_sheet || raw.sourceSheetName || raw.source_sheet;
out.candidateKey = out.candidateKey || out.candidate_key || raw.candidateKey || raw.candidate_key;

return { json: out, binary: item.binary };
});

const pending = items.filter((entry) => String(entry.json.contact_status || '').toLowerCase() === 'pending');

return pending.map((entry) => ({
