return items.map((entry) => {
  const start = new Date();
  start.setDate(start.getDate() + 2);
  start.setHours(10, 0, 0, 0);
  const end = new Date(start.getTime() + 30 * 60 * 1000);

  return {
    json: {
      ...entry.json,
      interviewStart: start.toISOString(),
      interviewEnd: end.toISOString()
    }
  };
});

function getTextFromItem(item) {
  const json = item.json || {};

  const candidates = [
    json.text,
    json.resumeText,
    json.extractedText,
    json.content,
    json.data,
    json.body,
  ];

  for (const value of candidates) {
    if (typeof value === 'string' && value.trim()) return value.trim();
  }

  return '';
}

function looksBad(text) {
  if (!text) return true;

  const cleaned = String(text).trim();
  if (cleaned.length < 120) return true;
  if (cleaned.startsWith('%PDF-')) return true;
  if (/^[\x00-\x08\x0B\x0C\x0E-\x1F]+$/.test(cleaned)) return true;
  if ((cleaned.match(/stream|endstream|obj|endobj|xref|trailer/gi) || []).length >= 3) return true;

  return false;
}

const items = $input.all();

for (const item of items) {
  const rawText = getTextFromItem(item);
  const binary = item.binary?.data;
  const mimeType = binary?.mimeType || '';
  const fileName = binary?.fileName || '';

  const needsOcr = looksBad(rawText) || mimeType === 'application/pdf' || /\.pdf$/i.test(fileName);

  item.json.resumeText = rawText;
  item.json.needsOcr = needsOcr;
  item.json.resumeTextStatus = needsOcr ? 'needs_ocr' : 'ok';
  item.json.resumeTextReason = !rawText
    ? 'no_text_found'
    : rawText.startsWith('%PDF-')
      ? 'pdf_binary_returned'
      : rawText.length < 120
        ? 'too_short'
        : 'extracted_ok';
}

return items;

